// Build script to bundle the JavaScript and WebAssembly modules
// This script uses esbuild to create a single bundle for the GitHub Action

import { build } from 'esbuild';
import { readFileSync, writeFileSync, copyFileSync, mkdirSync, existsSync } from 'fs';
import { dirname, join } from 'path';

// Ensure the dist directory exists
if (!existsSync('./dist')) {
  mkdirSync('./dist', { recursive: true });
}

// Bundle the JavaScript code
async function bundleJs() {
  try {
    // Build the main entry point
    await build({
      entryPoints: ['./src/index.ts'],
      bundle: true,
      platform: 'node',
      target: 'node16',
      format: 'esm',
      outfile: './dist/index.js',
      external: ['./pkg/*'],
      banner: {
        js: '// GitHub Action with WebAssembly optimization\n// This file was generated by the build-bundle.js script\n',
      },
    });

    console.log('JavaScript bundling completed successfully');
  } catch (error) {
    console.error('JavaScript bundling failed:', error);
    process.exit(1);
  }
}

// Copy the WebAssembly files to the dist directory
function copyWasmFiles() {
  try {
    // Check if the WebAssembly files exist
    if (!existsSync('./pkg/action_wasm_bg.wasm')) {
      console.error('WebAssembly files not found. Run `npm run build:wasm` first.');
      process.exit(1);
    }

    // Create the pkg directory in dist if it doesn't exist
    if (!existsSync('./dist/pkg')) {
      mkdirSync('./dist/pkg', { recursive: true });
    }

    // Copy the WebAssembly files
    copyFileSync('./pkg/action_wasm_bg.wasm', './dist/pkg/action_wasm_bg.wasm');
    copyFileSync('./pkg/action_wasm.js', './dist/pkg/action_wasm.js');

    console.log('WebAssembly files copied successfully');
  } catch (error) {
    console.error('Failed to copy WebAssembly files:', error);
    process.exit(1);
  }
}

// Main build function
async function main() {
  try {
    console.log('Starting build process...');

    // Bundle the JavaScript code
    await bundleJs();

    // Copy the WebAssembly files
    copyWasmFiles();

    console.log('Build completed successfully');
  } catch (error) {
    console.error('Build failed:', error);
    process.exit(1);
  }
}

// Run the main function
main();
